}): React.JSX.Element {
  return (
    <ActiveRivalCard
      key={entry.learnerId}
      copy={copy}
      entry={entry}
      isActionPending={presence.isActionPending}
      isCurrentLearner={isCurrentLearner}
      isPending={presence.pendingLearnerId === entry.learnerId}
      locale={locale}
      onChallenge={
        isCurrentLearner
          ? null
          : () => {
              void (async () => {
