            de: 'Duell-Lobby öffnen',
            en: 'Open duels lobby',
            pl: 'Otwórz lobby pojedynków',
          })}
        />
      </View>
    );
  } else {
    content = (
      <View style={{ gap: 12 }}>
        {duelSpotlight.entries.map((entry) => (
          <LiveDuelCard
            key={entry.sessionId}
            copy={copy}
            entry={entry}
            isAuthenticated={isAuthenticated}
            locale={locale}
          />
        ))}
      </View>
    );
  }

  return (
    <SectionCard
      title={copy({
        de: 'Live-Duelle',
        en: 'Live duels',
        pl: 'Na żywo w pojedynkach',
      })}
    >
      {content}
    </SectionCard>
  );
}

