import { kangurDuelLobbyEntrySchema, type KangurDuelLobbyEntry } from '@kangur/contracts/kangur-duels';
import type { KangurClientStorageAdapter } from '@kangur/platform';

import { MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT } from './homeDuelLobbyQuery';

const KANGUR_MOBILE_HOME_DUEL_INVITES_STORAGE_KEY =
  'kangur.mobile.home.duels.privateLobby';

const parsePersistedHomeDuelInvitesStore = (
  rawSnapshot: string | null,
): Record<string, KangurDuelLobbyEntry[]> => {
  const normalizedRawSnapshot = rawSnapshot?.trim() ?? '';
  if (!normalizedRawSnapshot) {
    return {};
  }

  try {
    const parsedSnapshot = JSON.parse(normalizedRawSnapshot) as unknown;
    if (
      !parsedSnapshot ||
      typeof parsedSnapshot !== 'object' ||
      Array.isArray(parsedSnapshot)
    ) {
      return {};
    }

    return Object.entries(parsedSnapshot).reduce<Record<string, KangurDuelLobbyEntry[]>>(
      (snapshot, [identityKey, value]) => {
        const parsedEntries = kangurDuelLobbyEntrySchema
          .array()
          .max(MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT)
          .safeParse(value);
        if (parsedEntries.success) {
          snapshot[identityKey] = parsedEntries.data;
        }
        return snapshot;
      },
      {},
    );
  } catch {
    return {};
  }
};

export const resolvePersistedKangurMobileHomeDuelInvites = ({
  learnerIdentity,
  storage,
}: {
  learnerIdentity: string;
  storage: KangurClientStorageAdapter;
}): KangurDuelLobbyEntry[] | null => {
  const store = parsePersistedHomeDuelInvitesStore(
    storage.getItem(KANGUR_MOBILE_HOME_DUEL_INVITES_STORAGE_KEY),
  );
  return store[learnerIdentity] ?? null;
};

export const persistKangurMobileHomeDuelInvites = ({
  entries,
  learnerIdentity,
  storage,
}: {
  entries: KangurDuelLobbyEntry[];
  learnerIdentity: string;
  storage: KangurClientStorageAdapter;
}): void => {
  if (!learnerIdentity) {
    return;
  }
  const currentStore = parsePersistedHomeDuelInvitesStore(
    storage.getItem(KANGUR_MOBILE_HOME_DUEL_INVITES_STORAGE_KEY),
  );
  const updatedStore = {
    ...currentStore,
    [learnerIdentity]: entries.slice(0, MOBILE_HOME_DUEL_LOBBY_QUERY_LIMIT),
  };
  storage.setItem(
    KANGUR_MOBILE_HOME_DUEL_INVITES_STORAGE_KEY,
    JSON.stringify(updatedStore),
  );
};

import {
  KANGUR_LESSON_CATALOG,
  getKangurPracticeOperationForLessonComponent,
  getLocalizedKangurCoreLessonTitle,
} from '@kangur/core';
import {
  createDefaultKangurProgressState,
  kangurLessonMasteryEntrySchema,
  type KangurLessonMastery,
  type KangurLessonMasteryEntry,
  type KangurProgressState,
} from '@kangur/contracts/kangur';
import type { Href } from 'expo-router';
import type { KangurClientStorageAdapter } from '@kangur/platform';

import { KANGUR_MOBILE_ACTIVE_LEARNER_STORAGE_KEY } from '../auth/mobileAuthStorageKeys';
import { createKangurLessonHref } from '../lessons/lessonHref';
import { createKangurPracticeHref } from '../practice/practiceHref';

const KANGUR_MOBILE_HOME_LESSON_CHECKPOINTS_STORAGE_KEY =
  'kangur.mobile.home.lessonCheckpoints';
const MOBILE_HOME_LESSON_CHECKPOINTS_SNAPSHOT_LIMIT = 2;

export type KangurMobileHomeLessonCheckpointItem = {
  attempts: number;
  bestScorePercent: number;
  componentId: string;
  emoji: string;
  lastCompletedAt: string;
  lastScorePercent: number;
  lessonHref: Href;
  masteryPercent: number;
  practiceHref: Href | null;
  title: string;
};

type PersistedHomeLessonCheckpointsStore = Record<string, KangurLessonMastery>;

const resolveTimestamp = (value: string | null): number => {
  if (value === null || value === '') {
    return Number.NEGATIVE_INFINITY;
  }

  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : Number.NEGATIVE_INFINITY;
};

const compareLessonCheckpointEntries = (
  [leftComponentId, leftMastery]: [string, KangurLessonMasteryEntry],
  [rightComponentId, rightMastery]: [string, KangurLessonMasteryEntry],
): number => {
  const timestampDelta =
    resolveTimestamp(rightMastery.lastCompletedAt) - resolveTimestamp(leftMastery.lastCompletedAt);
  if (timestampDelta !== 0) {
    return timestampDelta;
  }

  if (rightMastery.lastScorePercent !== leftMastery.lastScorePercent) {
    return rightMastery.lastScorePercent - leftMastery.lastScorePercent;
  }

  return leftComponentId.localeCompare(rightComponentId);
};

const selectRecentCheckpointEntries = (
  lessonMastery: KangurProgressState['lessonMastery'],
  limit: number,
): Array<[string, KangurLessonMasteryEntry]> => {
  const recentEntries: Array<[string, KangurLessonMasteryEntry]> = [];

  for (const [componentId, mastery] of Object.entries(lessonMastery)) {
    if (typeof mastery.lastCompletedAt !== 'string') {
      continue;
    }

    const candidateEntry: [string, KangurLessonMasteryEntry] = [componentId, mastery];
    const insertIndex = recentEntries.findIndex(
      (entry) => compareLessonCheckpointEntries(candidateEntry, entry) < 0,
    );

    if (insertIndex === -1) {
      recentEntries.push(candidateEntry);
    } else {
      recentEntries.splice(insertIndex, 0, candidateEntry);
    }

    if (recentEntries.length > limit) {
      recentEntries.length = limit;
    }
  }

  return recentEntries;
};

const parsePersistedHomeLessonCheckpointStore = (
  rawSnapshot: string | null,
): PersistedHomeLessonCheckpointsStore => {
  const normalizedRawSnapshot = rawSnapshot?.trim() ?? '';
  if (normalizedRawSnapshot.length === 0) {
    return {};
  }

  try {
    const parsedSnapshot = JSON.parse(normalizedRawSnapshot) as unknown;
    if (
      Boolean(parsedSnapshot) === false ||
      typeof parsedSnapshot !== 'object' ||
      Array.isArray(parsedSnapshot)
    ) {
      return {};
    }

    return Object.entries(parsedSnapshot).reduce<PersistedHomeLessonCheckpointsStore>(
      (snapshot, [identityKey, value]) => {
        if (Boolean(value) === false || typeof value !== 'object' || Array.isArray(value)) {
          return snapshot;
        }

        const normalizedLessonMastery = Object.entries(
          value as Record<string, unknown>,
        ).reduce<KangurLessonMastery>((masterySnapshot, [componentId, masteryValue]) => {
          const parsedEntry = kangurLessonMasteryEntrySchema.safeParse(masteryValue);
          if (parsedEntry.success) {
            masterySnapshot[componentId] = parsedEntry.data;
          }
          return masterySnapshot;
        }, {});

        return { ...snapshot, [identityKey]: normalizedLessonMastery };
      },
      {},
    );
  } catch {
    return {};
  }
};

const normalizeCheckpointLimit = (limit: number): number =>
  Math.min(
    MOBILE_HOME_LESSON_CHECKPOINTS_SNAPSHOT_LIMIT,
    Math.max(1, Math.round(limit)),
  );

const mapLessonCheckpointEntriesToItems = (
  entries: Array<[string, KangurLessonMasteryEntry]>,
  locale: string | null | undefined,
): KangurMobileHomeLessonCheckpointItem[] =>
  entries.map(([componentId, mastery]) => {
    const lessonCatalogEntry = KANGUR_LESSON_CATALOG[componentId];
    const practiceOperation = getKangurPracticeOperationForLessonComponent(
      componentId as Parameters<typeof getKangurPracticeOperationForLessonComponent>[0],
    );

    return {
      attempts: mastery.attempts,
      bestScorePercent: mastery.bestScorePercent,
      componentId,
      emoji: lessonCatalogEntry?.emoji ?? '📘',
      lastCompletedAt: mastery.lastCompletedAt ?? '',
      lastScorePercent: mastery.lastScorePercent,
      lessonHref: createKangurLessonHref(componentId),
      masteryPercent: mastery.masteryPercent,
      practiceHref: practiceOperation ? createKangurPracticeHref(practiceOperation) : null,
      title: getLocalizedKangurCoreLessonTitle(
        componentId,
        locale,
        lessonCatalogEntry?.title,
      ),
    };
  });

export const resolveKangurMobileHomeLessonCheckpointIdentity = (
  storage: KangurClientStorageAdapter,
): string => {
  const learnerIdentity =
    storage.getItem(KANGUR_MOBILE_ACTIVE_LEARNER_STORAGE_KEY)?.trim() ?? '';
  return learnerIdentity || 'guest';
};

export const buildPersistedKangurMobileHomeLessonCheckpointSnapshot = ({
  limit = MOBILE_HOME_LESSON_CHECKPOINTS_SNAPSHOT_LIMIT,
  progress,
}: {
  limit?: number;
  progress: KangurProgressState;
}): KangurLessonMastery =>
  Object.fromEntries(
    selectRecentCheckpointEntries(
      progress.lessonMastery,
      normalizeCheckpointLimit(limit),
    ),
  );

export const persistKangurMobileHomeLessonCheckpoints = ({
  learnerIdentity,
  snapshot,
  storage,
}: {
  learnerIdentity: string;
  snapshot: KangurLessonMastery;
  storage: KangurClientStorageAdapter;
}): void => {
  if (!learnerIdentity) {
    return;
  }
  const currentStore = parsePersistedHomeLessonCheckpointStore(
    storage.getItem(KANGUR_MOBILE_HOME_LESSON_CHECKPOINTS_STORAGE_KEY),
  );
  const updatedStore = {
    ...currentStore,
    [learnerIdentity]: snapshot,
  };
  storage.setItem(
    KANGUR_MOBILE_HOME_LESSON_CHECKPOINTS_STORAGE_KEY,
    JSON.stringify(updatedStore),
  );
};

export const resolvePersistedKangurMobileHomeLessonCheckpoints = ({
  learnerIdentity,
  limit = MOBILE_HOME_LESSON_CHECKPOINTS_SNAPSHOT_LIMIT,
  locale,
  storage,
}: {
  learnerIdentity: string;
  limit?: number;
  locale: string | null | undefined;
  storage: KangurClientStorageAdapter;
}): KangurMobileHomeLessonCheckpointItem[] | null => {
  const store = parsePersistedHomeLessonCheckpointStore(
    storage.getItem(KANGUR_MOBILE_HOME_LESSON_CHECKPOINTS_STORAGE_KEY),
  );
  const persistedSnapshot = store[learnerIdentity];
  if (!persistedSnapshot || Object.keys(persistedSnapshot).length === 0) {
    return null;
  }

  const progressSnapshot = createDefaultKangurProgressState();
  progressSnapshot.lessonMastery = persistedSnapshot;

  return mapLessonCheckpointEntriesToItems(
    selectRecentCheckpointEntries(
      progressSnapshot.lessonMastery,
      normalizeCheckpointLimit(limit),
    ),
    locale,
  );
};

import { startTransition, useEffect, useState } from 'react';
import { InteractionManager } from 'react-native';

const HOME_SCREEN_DEFERRED_PANELS_FALLBACK_TIMEOUT_MS = 240;
const deferredHomePanelCallbacks = new Set<() => void>();

let deferredHomePanelsInteractionTask:
  | ReturnType<typeof InteractionManager.runAfterInteractions>
  | null = null;
let deferredHomePanelsFallbackTimeoutId: ReturnType<typeof setTimeout> | null = null;
let cancelDeferredHomePanelsFrame = () => {};
let isDeferredHomePanelsFrameScheduled = false;

const scheduleDeferredHomePanelsFrame = (callback: () => void): (() => void) => {
  if (typeof requestAnimationFrame === 'function') {
    const frameId = requestAnimationFrame(() => {
      callback();
    });

    return () => {
      if (typeof cancelAnimationFrame === 'function') {
        cancelAnimationFrame(frameId);
      }
    };
  }

  const timeoutId = setTimeout(callback, 16);
  return () => {
    clearTimeout(timeoutId);
  };
};

const clearDeferredHomePanelsFallbackTimeout = (): void => {
  if (deferredHomePanelsFallbackTimeoutId === null) {
    return;
  }

  clearTimeout(deferredHomePanelsFallbackTimeoutId);
  deferredHomePanelsFallbackTimeoutId = null;
};

const clearDeferredHomePanelsSchedule = (): void => {
  clearDeferredHomePanelsFallbackTimeout();
  deferredHomePanelsInteractionTask?.cancel?.();
  deferredHomePanelsInteractionTask = null;
  cancelDeferredHomePanelsFrame();
  cancelDeferredHomePanelsFrame = () => {};
  isDeferredHomePanelsFrameScheduled = false;
};

const flushDeferredHomePanelCallbacks = (): void => {
  const callbacks = Array.from(deferredHomePanelCallbacks);
  deferredHomePanelCallbacks.clear();
  clearDeferredHomePanelsSchedule();

  if (callbacks.length === 0) {
    return;
  }

  startTransition(() => {
    for (const callback of callbacks) {
      callback();
    }
  });
};

const scheduleDeferredHomePanelsSettle = (): void => {
  if (isDeferredHomePanelsFrameScheduled) {
    return;
  }

  deferredHomePanelsInteractionTask = null;
  clearDeferredHomePanelsFallbackTimeout();
  isDeferredHomePanelsFrameScheduled = true;
  cancelDeferredHomePanelsFrame = scheduleDeferredHomePanelsFrame(
    flushDeferredHomePanelCallbacks,
  );
};

const ensureDeferredHomePanelsSchedule = (): void => {
  if (
    deferredHomePanelCallbacks.size === 0 ||
    deferredHomePanelsInteractionTask !== null ||
    deferredHomePanelsFallbackTimeoutId !== null ||
    isDeferredHomePanelsFrameScheduled
  ) {
    return;
  }

  deferredHomePanelsInteractionTask = InteractionManager.runAfterInteractions(
    scheduleDeferredHomePanelsSettle,
  );

  deferredHomePanelsFallbackTimeoutId = setTimeout(
    scheduleDeferredHomePanelsSettle,
    HOME_SCREEN_DEFERRED_PANELS_FALLBACK_TIMEOUT_MS,
  );
};

const scheduleDeferredHomePanelsCallback = (callback: () => void): (() => void) => {
  deferredHomePanelCallbacks.add(callback);
  ensureDeferredHomePanelsSchedule();

  return () => {
    deferredHomePanelCallbacks.delete(callback);

    if (deferredHomePanelCallbacks.size === 0) {
      clearDeferredHomePanelsSchedule();
    }
  };
};

export const useHomeScreenDeferredPanelSequence = <const TPanelKeys extends readonly string[]>(
  panelKeys: TPanelKeys,
  isBlocked: boolean,
): { [TIndex in keyof TPanelKeys]: boolean } => {
  const [readyCount, setReadyCount] = useState(0);
  const currentPanelKey = panelKeys[readyCount] ?? null;

  useEffect(() => {
    if (isBlocked) {
      setReadyCount(0);
      return;
    }

    if (currentPanelKey === null) {
      return;
    }

    let isDisposed = false;

    const cancelDeferredReadyState = scheduleDeferredHomePanelsCallback(() => {
      if (isDisposed) {
        return;
      }

      setReadyCount((currentReadyCount) => {
        if (currentReadyCount > readyCount) {
          return currentReadyCount;
        }

        return currentReadyCount + 1;
      });
    });

    return () => {
      isDisposed = true;
      cancelDeferredReadyState();
    };
  }, [currentPanelKey, isBlocked, readyCount]);

  return panelKeys.map((_, index) => index < readyCount) as {
    [TIndex in keyof TPanelKeys]: boolean;
  };
};

export const useHomeScreenDeferredPanelGroup = <const TPanelKeys extends readonly string[]>(
  panelKeys: TPanelKeys,
  isBlocked: boolean,
): { [TIndex in keyof TPanelKeys]: boolean } => {
  const [arePanelsReady, setArePanelsReady] = useState(false);
  const panelKeySignature = panelKeys.join('\u0000');

  useEffect(() => {
    if (isBlocked || panelKeys.length === 0) {
      setArePanelsReady(false);
      return;
    }

    setArePanelsReady(false);

    let isDisposed = false;

    const cancelDeferredReadyState = scheduleDeferredHomePanelsCallback(() => {
      if (isDisposed) {
        return;
      }

      setArePanelsReady(true);
    });

    return () => {
      isDisposed = true;
      cancelDeferredReadyState();
    };
  }, [isBlocked, panelKeySignature, panelKeys.length]);

  return panelKeys.map(() => arePanelsReady) as {
    [TIndex in keyof TPanelKeys]: boolean;
  };
};

export const useHomeScreenDeferredPanels = (
  panelKey: string,
  isBlocked: boolean,
): boolean => {
  const [arePanelsReady, setArePanelsReady] = useState(false);

  useEffect(() => {
    if (isBlocked) {
      setArePanelsReady(false);
      return undefined;
    }

    setArePanelsReady(false);

    let isDisposed = false;

    const settleReadyState = (): void => {
      if (isDisposed) {
        return;
      }

      setArePanelsReady(true);
    };

    const cancelDeferredReadyState = scheduleDeferredHomePanelsCallback(
      settleReadyState,
    );

    return () => {
      isDisposed = true;
      cancelDeferredReadyState();
    };
  }, [isBlocked, panelKey]);

  return arePanelsReady;
};

import {
  getLocalizedKangurMetadataBadgeName,
  KANGUR_BADGES,
} from '@kangur/core';
import { useMemo } from 'react';

import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileHomeProgressSnapshot } from './KangurMobileHomeProgressSnapshotContext';

export type KangurMobileHomeBadgeItem = {
  emoji: string;
  id: string;
  name: string;
};

type UseKangurMobileHomeBadgesResult = {
  recentBadges: KangurMobileHomeBadgeItem[];
  remainingBadges: number;
  totalBadges: number;
  unlockedBadges: number;
};

const HOME_BADGE_RECENT_LIMIT = 3;

let badgeById: Map<string, { id: string; emoji: string; name: string }> | null = null;

const getBadgeById = () => {
  if (!badgeById) {
    badgeById = new Map(KANGUR_BADGES.map((badge) => [badge.id, badge]));
  }
  return badgeById;
};

export const useKangurMobileHomeBadges =
  (): UseKangurMobileHomeBadgesResult => {
    const { locale } = useKangurMobileI18n();
    const progress = useKangurMobileHomeProgressSnapshot();

    return useMemo(() => {
      const badges = getBadgeById();

      const unlockedBadgeIds = Array.from(
        new Set(progress.badges.filter((badgeId) => badges.has(badgeId))),
      );
      const recentBadges = unlockedBadgeIds
        .slice(-HOME_BADGE_RECENT_LIMIT)
        .reverse()
        .map((badgeId) => {
          const badge = badges.get(badgeId);

          if (!badge) {
            return null;
          }

          return {
            emoji: badge.emoji,
            id: badge.id,
            name: getLocalizedKangurMetadataBadgeName(
              badge.id,
              badge.name,
              locale,
            ),
          };
        })
        .filter((badge): badge is KangurMobileHomeBadgeItem => badge !== null);
      const totalBadges = KANGUR_BADGES.length;
      const unlockedBadges = unlockedBadgeIds.length;

      return {
        recentBadges,
        remainingBadges: Math.max(0, totalBadges - unlockedBadges),
        totalBadges,
        unlockedBadges,
      };
    }, [locale, progress]);
  };

