import type { KangurScore } from '@kangur/contracts/kangur';
import type { KangurClientStorageAdapter } from '@kangur/platform';
import { useEffect, useMemo } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { resolveKangurMobileScoreScope } from '../profile/mobileScoreScope';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import {
  persistKangurMobileRecentResults,
  resolvePersistedKangurMobileRecentResults,
} from '../scores/persistedKangurMobileRecentResults';
import { useKangurMobileScoreHistory } from '../scores/useKangurMobileScoreHistory';

type UseKangurMobileRecentResultsOptions = {
  enabled?: boolean;
  limit?: number;
};

type UseKangurMobileRecentResultsResult = {
  error: string | null;
  isEnabled: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  refresh: () => Promise<void>;
  results: KangurScore[];
};

const getPersistedResults = (
  identityKey: string,
  limit: number,
  storage: KangurClientStorageAdapter,
): KangurScore[] => {
  return resolvePersistedKangurMobileRecentResults({
    identityKey,
    limit,
    storage,
  });
};

const getErrorMessage = (
  copy: (params: { de: string; en: string; pl: string }) => string,
): string => {
  return copy({
    de: 'Die letzten Ergebnisse konnten nicht geladen werden.',
    en: 'Could not load the recent results.',
    pl: 'Nie udało się pobrać ostatnich wyników.',
  });
};

type ResultsQuery = {
  isEnabled: boolean;
  isLoading: boolean;
  isPlaceholderData: boolean;
  isRestoringAuth: boolean;
  error: unknown;
};

const canPersist = (
  identityKey: string | null,
  resultsQuery: ResultsQuery,
): boolean => identityKey !== null && shouldPersist(identityKey, resultsQuery);

export const useKangurMobileRecentResults = (
  options: UseKangurMobileRecentResultsOptions = {},
): UseKangurMobileRecentResultsResult => {
  const { copy } = useKangurMobileI18n();
  const { session } = useKangurMobileAuth();
  const { storage } = useKangurMobileRuntime();
  const limit =
    typeof options.limit === 'number' && options.limit > 0
      ? Math.round(options.limit)
      : 3;
  const isQueryEnabled = options.enabled ?? true;
  const scoreScope = resolveKangurMobileScoreScope(session.user);
  const scoreScopeIdentityKey = scoreScope?.identityKey ?? null;

  const persistedResults = useMemo(
    () =>
      scoreScopeIdentityKey !== null
        ? getPersistedResults(scoreScopeIdentityKey, limit, storage)
        : null,
    [limit, scoreScopeIdentityKey, storage],
  );
  const resultsQuery = useKangurMobileScoreHistory({
    enabled: isQueryEnabled,
    limit,
    placeholderData: persistedResults ?? undefined,
    sort: '-created_date',
  });
  const results = (
    resultsQuery.isEnabled || !persistedResults ? resultsQuery.scores : persistedResults
  ).slice(0, limit);

  useEffect(() => {
    if (canPersist(scoreScopeIdentityKey, resultsQuery)) {
      persistKangurMobileRecentResults({
        identityKey: scoreScopeIdentityKey!,
        results,
        storage,
      });
    }
  }, [
    results,
    resultsQuery.error,
    resultsQuery.isEnabled,
    resultsQuery.isLoading,
    resultsQuery.isPlaceholderData,
    resultsQuery.isRestoringAuth,
    scoreScopeIdentityKey,
    storage,
  ]);

  return {
    error: resultsQuery.error instanceof Error ? getErrorMessage(copy) : null,
    isEnabled: resultsQuery.isEnabled,
    isLoading: resultsQuery.isLoading,
    isRestoringAuth: resultsQuery.isRestoringAuth,
    refresh: async () => {
      if (resultsQuery.isEnabled) {
        await resultsQuery.refresh();
      }
    },
    results,
  };
};

import type { KangurScore } from '@kangur/contracts/kangur';
import { resolveKangurLessonFocusForPracticeOperation } from '@kangur/core';
import { useEffect, useMemo } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import {
  buildKangurMobileTrainingFocus,
  type KangurMobileOperationPerformance,
} from '../scores/mobileScoreSummary';
import {
  persistKangurMobileTrainingFocus,
  resolvePersistedKangurMobileTrainingFocus,
} from '../scores/persistedKangurMobileTrainingFocus';
import { persistKangurMobileRecentResults } from '../scores/persistedKangurMobileRecentResults';
import { useKangurMobileResults } from '../scores/useKangurMobileResults';
import { resolveKangurMobileScoreScope } from '../profile/mobileScoreScope';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';

type UseKangurMobileTrainingFocusResult = {
  error: string | null;
  isEnabled: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  recentResults: KangurScore[];
  refresh: () => Promise<void>;
  strongestLessonFocus: string | null;
  strongestOperation: KangurMobileOperationPerformance | null;
  weakestLessonFocus: string | null;
  weakestOperation: KangurMobileOperationPerformance | null;
};

type UseKangurMobileTrainingFocusOptions = {
  enabled?: boolean;
  recentResultsLimit?: number;
};

export const useKangurMobileTrainingFocus =
  (
    options: UseKangurMobileTrainingFocusOptions = {},
  ): UseKangurMobileTrainingFocusResult => {
    const { session } = useKangurMobileAuth();
    const { storage } = useKangurMobileRuntime();
    const recentResultsLimit =
      typeof options.recentResultsLimit === 'number' &&
      options.recentResultsLimit > 0
        ? Math.round(options.recentResultsLimit)
        : 3;
    const results = useKangurMobileResults({
      enabled: options.enabled,
    });
    const scoreScopeIdentityKey =
      resolveKangurMobileScoreScope(session.user)?.identityKey ?? null;
    const persistedFocus = useMemo(
      () =>
        scoreScopeIdentityKey
          ? resolvePersistedKangurMobileTrainingFocus({
              identityKey: scoreScopeIdentityKey,
              storage,
            })
          : null,
      [scoreScopeIdentityKey, storage],
    );
    const liveFocus = useMemo(
      () => buildKangurMobileTrainingFocus(results.operationPerformance),
      [results.operationPerformance],
    );
    const recentResults = useMemo(
      () => results.scores.slice(0, recentResultsLimit),
      [recentResultsLimit, results.scores],
    );
    const hasResolvedLiveFocus =
      results.isEnabled &&
      !results.isLoading &&
      !results.isRestoringAuth &&
      !results.error;
    const focus = hasResolvedLiveFocus
      ? liveFocus
      : persistedFocus ?? liveFocus;

    useEffect(() => {
      if (!scoreScopeIdentityKey || !hasResolvedLiveFocus) {
        return;
      }

      persistKangurMobileTrainingFocus({
        focus: liveFocus,
        identityKey: scoreScopeIdentityKey,
        storage,
      });
      persistKangurMobileRecentResults({
        identityKey: scoreScopeIdentityKey,
        results: recentResults,
        storage,
      });
    }, [
      hasResolvedLiveFocus,
      liveFocus,
      recentResults,
      scoreScopeIdentityKey,
      storage,
    ]);

    return {
      error: results.error,
      isEnabled: results.isEnabled,
      isLoading: results.isLoading,
      isRestoringAuth: results.isRestoringAuth,
      recentResults,
      refresh: results.refresh,
      strongestLessonFocus: focus.strongestOperation
        ? resolveKangurLessonFocusForPracticeOperation(
            focus.strongestOperation.operation,
          )
        : null,
      strongestOperation: focus.strongestOperation,
      weakestLessonFocus: focus.weakestOperation
        ? resolveKangurLessonFocusForPracticeOperation(
            focus.weakestOperation.operation,
          )
        : null,
      weakestOperation: focus.weakestOperation,
    };
  };

