  verticalPadding?: number;
};

export type KangurMobileLinkButtonProps = {
  accessibilityHint?: string;
  accessibilityLabel?: string;
  borderRadius?: number;
  centered?: boolean;
  href: Href;
  label: string;
  minHeight?: number;
  onPress?: () => void;
  stretch?: boolean;
  style?: StyleProp<ViewStyle>;
  textStyle?: StyleProp<TextStyle>;
