  minHeight,
  horizontalPadding,
  verticalPadding,
}: {
  fullWidth: boolean;
  borderRadius: number;
  selected: boolean;
  selectedBorderColor: string;
  selectedBackgroundColor: string;
  centered: boolean;
  minHeight?: number;
  horizontalPadding: number;
  verticalPadding: number;
}): ViewStyle => ({
