  selectedTextColor,
  idleTextColor,
  centered,
  fullWidth,
}: {
  selected: boolean;
  selectedTextColor: string;
  idleTextColor: string;
  centered: boolean;
  fullWidth: boolean;
}): TextStyle => ({
  color: selected ? selectedTextColor : idleTextColor,
  fontSize: 13,
